//! Spec-compliance tests: Comments (ISO 29500-1 §17.13.4)
//!
//! These tests verify our implementation against specific OOXML comment
//! constructs. Tests marked `#[ignore]` document known gaps.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{BlockNode, CommentStory, InlineNode};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/comments";

// ── helpers ──────────────────────────────────────────────────────────────
/// Find a CommentStory by ID.
fn find_comment<'a>(comments: &'a [CommentStory], id: &str) -> Option<&'a CommentStory> {
    comments.iter().find(|c| c.id == id)
}

/// Check if any inline in a paragraph matches the given predicate.
fn has_inline(para: &stemma::ParagraphNode, pred: impl Fn(&InlineNode) -> bool) -> bool {
    para.all_inlines().any(pred)
}

// ── basic-comment ────────────────────────────────────────────────────────

/// ISO 29500-1 §17.13.4.2: Comment story parsed from word/comments.xml.
/// Verifies that the basic comment fixture produces at least one CommentStory
/// with the correct id, author, and text content.
#[test]
fn spec_comment_story_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "basic-comment");

    assert!(
        !doc.comments.is_empty(),
        "comments vec should not be empty — basic comment fixture has one comment"
    );

    let comment = find_comment(&doc.comments, "1").expect("should find comment with id=1");

    assert_eq!(
        comment.author.as_deref(),
        Some("Test Author"),
        "comment author should be 'Test Author'"
    );

    // Verify comment has block content
    assert!(
        !comment.blocks.is_empty(),
        "comment should have at least one block of content"
    );

    // Verify the comment text content
    let text: String = comment
        .blocks
        .iter()
        .filter_map(|b| match &b.block {
            BlockNode::Paragraph(p) => {
                let t: String = p
                    .all_inlines()
                    .filter_map(|i| match i {
                        InlineNode::Text(t) => Some(t.text.as_str()),
                        _ => None,
                    })
                    .collect();
                Some(t)
            }
            _ => None,
        })
        .collect();

    assert!(
        text.contains("This is a comment"),
        "comment text should contain 'This is a comment', got: {text:?}"
    );
}

/// ISO 29500-1 §17.13.4.2/3: commentRangeStart and commentRangeEnd markers
/// should appear in the paragraph's inline nodes.
#[test]
fn spec_comment_range_markers_in_body() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "basic-comment");
    let paras = common::all_paragraphs(&doc);

    assert!(!paras.is_empty(), "should have at least one paragraph");

    // Look for CommentRangeStart/End or Decoration with CommentRange kind
    let all_inlines: Vec<&InlineNode> = paras.iter().flat_map(|p| p.all_inlines()).collect();

    let has_range_start = all_inlines.iter().any(|i| {
        matches!(
            i,
            InlineNode::CommentRangeStart { id } if id == "1"
        )
    });

    let has_range_end = all_inlines.iter().any(|i| {
        matches!(
            i,
            InlineNode::CommentRangeEnd { id } if id == "1"
        )
    });

    let has_decoration_range = all_inlines.iter().any(|i| {
        matches!(
            i,
            InlineNode::Decoration(d) if d.kind == stemma::DecorationType::CommentRange
        )
    });

    assert!(
        has_range_start || has_decoration_range,
        "paragraph should contain CommentRangeStart{{id: \"1\"}} or a CommentRange decoration. \
         Found inlines: {all_inlines:?}"
    );

    assert!(
        has_range_end || has_decoration_range,
        "paragraph should contain CommentRangeEnd{{id: \"1\"}} or a CommentRange decoration. \
         Found inlines: {all_inlines:?}"
    );
}

/// ISO 29500-1 §17.13.4.5: commentReference links the body location to
/// the comment story. Should appear as an InlineNode in the paragraph.
#[test]
fn spec_comment_reference_in_body() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "basic-comment");
    let paras = common::all_paragraphs(&doc);

    let all_inlines: Vec<&InlineNode> = paras.iter().flat_map(|p| p.all_inlines()).collect();

    let has_reference = all_inlines.iter().any(|i| {
        matches!(
            i,
            InlineNode::CommentReference { id } if id == "1"
        )
    });

    // CommentReference might also be represented as a NoteReference or Decoration
    let has_any_reference_form = has_reference
        || all_inlines.iter().any(|i| match i {
            InlineNode::OpaqueInline(o) => {
                // Check if it's a comment reference opaque
                format!("{:?}", o.kind).contains("Comment")
            }
            _ => false,
        });

    assert!(
        has_any_reference_form,
        "paragraph should contain a CommentReference{{id: \"1\"}} inline. \
         Found inlines: {all_inlines:?}"
    );
}

/// ISO 29500-1 §17.13.4.2: Comment author and date should be populated.
#[test]
fn spec_comment_author_and_date() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "basic-comment");

    let comment = find_comment(&doc.comments, "1").expect("should find comment with id=1");

    assert_eq!(
        comment.author.as_deref(),
        Some("Test Author"),
        "author should be 'Test Author'"
    );

    assert!(comment.date.is_some(), "date should be populated");

    assert_eq!(
        comment.date.as_deref(),
        Some("2025-01-01T00:00:00Z"),
        "date should be '2025-01-01T00:00:00Z'"
    );
}

// ── multi-paragraph-comment ──────────────────────────────────────────────

/// ISO 29500-1 §17.13.4.2/3: Comment range spanning multiple paragraphs.
/// commentRangeStart in first paragraph, commentRangeEnd in third paragraph.
#[test]
fn spec_multi_paragraph_comment_range() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "multi-paragraph-comment");
    let paras = common::all_paragraphs(&doc);

    assert!(
        paras.len() >= 3,
        "should have at least 3 paragraphs, got {}",
        paras.len()
    );

    // Check that the comment story is parsed
    let comment = find_comment(&doc.comments, "1").expect("should find comment with id=1");
    assert_eq!(comment.author.as_deref(), Some("Test Author"));

    // Check that CommentRangeStart is in the first paragraph
    let first_has_start = has_inline(paras[0], |i| {
        matches!(
            i,
            InlineNode::CommentRangeStart { id } if id == "1"
        )
    }) || has_inline(paras[0], |i| {
        matches!(
            i,
            InlineNode::Decoration(d) if d.kind == stemma::DecorationType::CommentRange
        )
    });

    // Check that CommentRangeEnd is in the last paragraph (index 2+)
    let last_has_end = paras.iter().skip(2).any(|p| {
        has_inline(p, |i| {
            matches!(
                i,
                InlineNode::CommentRangeEnd { id } if id == "1"
            )
        }) || has_inline(p, |i| {
            matches!(
                i,
                InlineNode::Decoration(d) if d.kind == stemma::DecorationType::CommentRange
            )
        })
    });

    assert!(
        first_has_start,
        "first paragraph should contain CommentRangeStart or CommentRange decoration"
    );

    assert!(
        last_has_end,
        "paragraph 3+ should contain CommentRangeEnd or CommentRange decoration"
    );
}

// ── multiple-comments ────────────────────────────────────────────────────

/// ISO 29500-1 §17.13.4: Multiple independent comments with distinct IDs.
#[test]
fn spec_multiple_independent_comments() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "multiple-comments");

    assert!(
        doc.comments.len() >= 2,
        "should have at least 2 comments, got {}",
        doc.comments.len()
    );

    let c1 = find_comment(&doc.comments, "1").expect("should find comment with id=1");
    let c2 = find_comment(&doc.comments, "2").expect("should find comment with id=2");

    assert_eq!(c1.author.as_deref(), Some("Author One"));
    assert_eq!(c2.author.as_deref(), Some("Author Two"));

    // Verify different content
    let text1: String = c1
        .blocks
        .iter()
        .filter_map(|b| match &b.block {
            BlockNode::Paragraph(p) => Some(
                p.all_inlines()
                    .filter_map(|i| match i {
                        InlineNode::Text(t) => Some(t.text.clone()),
                        _ => None,
                    })
                    .collect::<String>(),
            ),
            _ => None,
        })
        .collect();

    let text2: String = c2
        .blocks
        .iter()
        .filter_map(|b| match &b.block {
            BlockNode::Paragraph(p) => Some(
                p.all_inlines()
                    .filter_map(|i| match i {
                        InlineNode::Text(t) => Some(t.text.clone()),
                        _ => None,
                    })
                    .collect::<String>(),
            ),
            _ => None,
        })
        .collect();

    assert_ne!(
        text1, text2,
        "the two comments should have different content"
    );
    assert!(
        text1.contains("first range"),
        "comment 1 should mention 'first range', got: {text1:?}"
    );
    assert!(
        text2.contains("second range"),
        "comment 2 should mention 'second range', got: {text2:?}"
    );
}

// ── comment-with-reply ───────────────────────────────────────────────────

/// ISO 29500-1 §17.13.4: Comment with a reply — both comments should be
/// parsed as separate CommentStory entries. Threading metadata is not
/// modeled in the domain, but both stories should exist.
#[test]
fn spec_comment_with_reply_both_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "comment-with-reply");

    assert!(
        doc.comments.len() >= 2,
        "should have at least 2 comments (parent + reply), got {}",
        doc.comments.len()
    );

    let parent = find_comment(&doc.comments, "1").expect("should find parent comment with id=1");
    let reply = find_comment(&doc.comments, "2").expect("should find reply comment with id=2");

    assert_eq!(parent.author.as_deref(), Some("Test Author"));
    assert_eq!(reply.author.as_deref(), Some("Reply Author"));

    // Verify reply has content
    let reply_text: String = reply
        .blocks
        .iter()
        .filter_map(|b| match &b.block {
            BlockNode::Paragraph(p) => Some(
                p.all_inlines()
                    .filter_map(|i| match i {
                        InlineNode::Text(t) => Some(t.text.clone()),
                        _ => None,
                    })
                    .collect::<String>(),
            ),
            _ => None,
        })
        .collect();

    assert!(
        reply_text.contains("Reply to parent"),
        "reply comment should contain 'Reply to parent', got: {reply_text:?}"
    );
}
